import { createSlice, PayloadAction, createSelector } from '@reduxjs/toolkit';

interface UserProfile {
  id: string;
  name: string;
  email: string;
  role: 'admin' | 'editor' | 'viewer';
}

interface Preferences {
  theme: 'light' | 'dark' | 'system';
  language: string;
  notifications: boolean;
  compactMode: boolean;
}

interface WorkspaceItem {
  id: string;
  title: string;
  type: 'document' | 'spreadsheet' | 'presentation';
  updatedAt: string;
  ownerId: string;
}

interface WorkspaceState {
  profile: UserProfile | null;
  preferences: Preferences;
  itemsById: Record<string, WorkspaceItem>;
  selectedItemId: string | null;
  isLoading: boolean;
  error: string | null;
}

const initialState: WorkspaceState = {
  profile: null,
  preferences: {
    theme: 'system',
    language: 'en',
    notifications: true,
    compactMode: false,
  },
  itemsById: {},
  selectedItemId: null,
  isLoading: false,
  error: null,
};

const workspaceSlice = createSlice({
  name: 'workspace',
  initialState,
  reducers: {
    setProfile(state, action: PayloadAction<UserProfile>) {
      state.profile = action.payload;
    },
    updatePreferences(state, action: PayloadAction<Partial<Preferences>>) {
      Object.assign(state.preferences, action.payload);
    },
    setItems(state, action: PayloadAction<WorkspaceItem[]>) {
      state.itemsById = {};
      for (const item of action.payload) {
        state.itemsById[item.id] = item;
      }
    },
    addItem(state, action: PayloadAction<WorkspaceItem>) {
      state.itemsById[action.payload.id] = action.payload;
    },
    removeItem(state, action: PayloadAction<string>) {
      delete state.itemsById[action.payload];
    },
    selectItem(state, action: PayloadAction<string | null>) {
      state.selectedItemId = action.payload;
    },
    setLoading(state, action: PayloadAction<boolean>) {
      state.isLoading = action.payload;
    },
    setError(state, action: PayloadAction<string | null>) {
      state.error = action.payload;
    },
  },
});

export const {
  setProfile, updatePreferences, setItems, addItem,
  removeItem, selectItem, setLoading, setError,
} = workspaceSlice.actions;

export default workspaceSlice.reducer;

export const selectProfile = (state: { workspace: WorkspaceState }) => state.workspace.profile;
export const selectPreferences = (state: { workspace: WorkspaceState }) => state.workspace.preferences;
export const selectAllItems = createSelector(
  (state: { workspace: WorkspaceState }) => state.workspace.itemsById,
  (itemsById) => Object.values(itemsById),
);
export const selectItemCount = createSelector(selectAllItems, (items) => items.length);
export const selectSelectedItem = (state: { workspace: WorkspaceState }) =>
  state.workspace.selectedItemId ? state.workspace.itemsById[state.workspace.selectedItemId] : null;

